{
  "learning_outcomes": [
    {
      "unit_name": "Physical World and Measurement",
      "chapter_name": "Units and Measurements",
      "topic": "SI Units, Significant Figures, Uncertainty, Dimensions",
      "outcomes": [
        "Apply knowledge of fundamental and derived SI units for physical quantities.",
        "Determine the number of significant figures in measured values and calculate results with appropriate precision.",
        "Estimate and determine the uncertainty in experimental results using standard rules.",
        "Derive dimensions of physical quantities and apply dimensional analysis to verify equations or derive relationships."
      ]
    },
    {
      "unit_name": "Kinematics",
      "chapter_name": "Motion in a Straight Line",
      "topic": "Calculus-based Kinematics, Graphs, Equations of Motion",
      "outcomes": [
        "Use elementary concepts of differentiation and integration to describe kinematic quantities like velocity and acceleration.",
        "Distinguish between average speed/velocity and instantaneous velocity in various motion scenarios.",
        "Interpret position-time and velocity-time graphs to analyze uniform and non-uniform accelerated motion.",
        "Apply graphical methods and calculus-based relations for uniformly accelerated motion."
      ]
    },
    {
      "unit_name": "Kinematics",
      "chapter_name": "Motion in a Plane",
      "topic": "Vector Operations, Projectile Motion, Circular Motion",
      "outcomes": [
        "Perform addition, subtraction, scalar multiplication, and dot/cross products on vectors; resolve vectors into rectangular components.",
        "Analyze projectile motion by resolving initial velocity and applying kinematic equations in two dimensions.",
        "Describe uniform circular motion including the relationship between linear speed, angular speed, and centripetal acceleration."
      ]
    },
    {
      "unit_name": "Laws of Motion",
      "chapter_name": "Laws of Motion",
      "topic": "Newton's Laws, Momentum Conservation, Impulse, Friction",
      "outcomes": [
        "Explain the concept of inertia and apply Newton's first law to identify equilibrium conditions.",
        "Apply Newton's second law (F=ma) and the concept of impulse to solve problems involving force and change in motion.",
        "Utilize Newton's third law and the principle of conservation of linear momentum for systems interacting via forces."
      ]
    },
    {
      "unit_name": "Work, Energy and Power",
      "chapter_name": "Work, Energy and Power",
      "topic": "Core Concepts and Relationships in Work, Energy and Power",
      "outcomes": [
        "Understand the core concepts of Work, Energy and Power.",
        "Apply key ideas from Work, Energy and Power to solve curriculum-aligned problems.",
        "Analyze relationships between major concepts in Work, Energy and Power."
      ]
    },
    {
      "unit_name": "Motion of System of Particles and Rigid Body",
      "chapter_name": "System of Particles and Rotational Motion",
      "topic": "Conservation of Momentum, Centre of Mass",
      "outcomes": [
        "Apply the law of conservation of linear momentum to analyze centre of mass motion in a system of particles."
      ]
    },
    {
      "unit_name": "Gravitation",
      "chapter_name": "Gravitation",
      "topic": "Universal Gravitation, Orbital Mechanics",
      "outcomes": [
        "Apply the Universal Law of Gravitation to calculate gravitational force between masses."
      ]
    },
    {
      "unit_name": "Properties of Bulk Matter",
      "chapter_name": "Mechanical Properties of Solids",
      "topic": "Elasticity, Stress-Strain Relationships",
      "outcomes": [
        "Apply Hooke's Law to determine the relationship between stress and strain in elastic materials."
      ]
    },
    {
      "unit_name": "Properties of Bulk Matter",
      "chapter_name": "Mechanical Properties of Fluids",
      "topic": "Viscosity, Terminal Velocity, Stokes' Law",
      "outcomes": [
        "Apply Stokes' Law and the concept of terminal velocity to analyze motion through viscous fluids."
      ]
    },
    {
      "unit_name": "Properties of Bulk Matter",
      "chapter_name": "Thermal Properties of Matter",
      "topic": "Calorimetry, Specific Heat Capacity",
      "outcomes": [
        "Apply the principles of calorimetry and conservation of energy to solve problems involving specific heat capacity."
      ]
    },
    {
      "unit_name": "Thermodynamics",
      "chapter_name": "Thermodynamics",
      "topic": "Heat, Work, Internal Energy, Laws of Thermodynamics",
      "outcomes": [
        "Understand heat, work and internal energy concepts.",
        "Apply the first law of thermodynamics to physical processes.",
        "Analyze state variables and equations of state in relation to the second law.",
        "Differentiate between isothermal and adiabatic changes in gaseous states."
      ]
    },
    {
      "unit_name": "Behaviour of Perfect Gases and Kinetic Theory of Gases",
      "chapter_name": "Kinetic Theory",
      "topic": "Pressure, Temperature, RMS Speed, Equipartition of Energy",
      "outcomes": [
        "Explain kinetic theory assumptions and derive the concept of pressure.",
        "Interpret temperature through kinetic energy and calculate RMS speed.",
        "Apply the law of equipartition of energy to specific heat capacities."
      ]
    },
    {
      "unit_name": "Oscillations and Waves",
      "chapter_name": "Oscillations",
      "topic": "Periodic Functions, Simple Harmonic Motion (S.H.M)",
      "outcomes": [
        "Describe periodic functions and their applications in displacement over time.",
        "Analyze Simple Harmonic Motion (S.H.M) characteristics."
      ]
    },
    {
      "unit_name": "Oscillations and Waves",
      "chapter_name": "Waves",
      "topic": "Core Concepts of Waves",
      "outcomes": [
        "Understand the core concepts of Waves.",
        "Apply key ideas from Waves to solve curriculum-aligned problems.",
        "Analyze relationships between major concepts in Waves."
      ]
    }
  ]
}
